vtest(
  'v1 → latest migration chain folds every step',
  'A v1 row in a v1→v2→v3 schema emerges with every field added by intermediate migrations.',
  async () => {
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => ({ ...p, b: 'B' }))
      .evolve('v3', { c: Schema.Number }, (p) => ({ ...p, c: 3 }))
      .build();
    const out = await Effect.runPromise(s.decode({ _v: 'v1', a: 'A' }));
    expect(out).toEqual({ a: 'A', b: 'B', c: 3 });
  },
);

vtest(
  'migration runs only for versions strictly older than the row',
  'A v2 row in the same v1→v2→v3 chain runs only the v2→v3 migration; the v1→v2 migration is skipped.',
  async () => {
    let v1Calls = 0;
    let v2Calls = 0;
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => {
        v1Calls += 1;
        return { ...p, b: 'B' };
      })
      .evolve('v3', { c: Schema.Number }, (p) => {
        v2Calls += 1;
        return { ...p, c: 3 };
      })
      .build();
    await Effect.runPromise(s.decode({ _v: 'v2', a: 'A', b: 'b' }));
    expect(v1Calls).toBe(0);
    expect(v2Calls).toBe(1);
  },
);

vtest(
  'missing _v falls back to latestVersion',
  'No migrations run; the row is decoded directly against the latest struct.',
  async () => {
    let migrated = 0;
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => {
        migrated += 1;
        return { ...p, b: 'B' };
      })
      .build();
    const out = await Effect.runPromise(s.decode({ a: 'A', b: 'B' }));
    expect(out).toEqual({ a: 'A', b: 'B' });
    expect(migrated).toBe(0);
  },
);

vtest(
  'unknown _v fails with Unknown schema version: <v>',
  'The message includes the offending version string so callers can diagnose stale producers without inspecting the chain.',
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const result = await Effect.runPromise(
      s.decode({ _v: 'v99', a: 'A' }).pipe(Effect.either),
    );
    expect(result._tag).toBe('Left');
    if (result._tag === 'Left') {
      expect(result.left).toBeInstanceOf(ESchemaError);
      expect(result.left.message).toContain('v99');
    }
  },
);

vtest(
  'decode of a bad shape fails with ESchemaError(Decode failed)',
  'A type mismatch in the input fails the struct decoder and surfaces as a wrapped `ESchemaError`.',
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const result = await Effect.runPromise(
      s.decode({ _v: 'v1', a: 42 }).pipe(Effect.either),
    );
    expect(result._tag).toBe('Left');
    if (result._tag === 'Left') {
      expect(result.left).toBeInstanceOf(ESchemaError);
      expect(result.left.message).toBe('Decode failed');
      expect(result.left.cause).toBeDefined();
    }
  },
);

vtest(
  'EntityESchema decode succeeds with idField present',
  'A row with `id` is decoded; the id is part of the output.',
  async () => {
    const s = EntityESchema.make('User', 'id', {
      name: Schema.String,
    }).build();
    const out = await Effect.runPromise(
      s.decode({ _v: 'v1', id: 'u1', name: 'Alice' }),
    );
    expect(out).toEqual({ id: 'u1', name: 'Alice' });
  },
);

vtest(
  'EntityESchema decode fails without idField',
  'A row missing `id` fails the struct decoder; the wrapped error is `Decode failed`.',
  async () => {
    const s = EntityESchema.make('User', 'id', {
      name: Schema.String,
    }).build();
    const result = await Effect.runPromise(
      s.decode({ _v: 'v1', name: 'Alice' }).pipe(Effect.either),
    );
    expect(result._tag).toBe('Left');
    if (result._tag === 'Left') {
      expect((result.left as ESchemaError).message).toBe('Decode failed');
    }
  },
);

vtest(
  'encode stamps the latest _v on a v1-only schema',
  'A freshly-made schema encodes to `_v: "v1"`.',
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const out = await Effect.runPromise(s.encode({ a: 'x' }));
    expect(out._v).toBe('v1');
  },
);

vtest(
  'encode stamps the latest _v after several evolutions',
  'After two evolutions the stamp is `v3`, regardless of what shape the value came from.',
  async () => {
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => ({ ...p, b: '' }))
      .evolve('v3', { c: Schema.Number }, (p) => ({ ...p, c: 0 }))
      .build();
    const out = await Effect.runPromise(s.encode({ a: 'x', b: 'y', c: 1 }));
    expect(out._v).toBe('v3');
  },
);

vtest(
  'encode runs Effect Schema transforms in the encode direction',
  'A `Schema.transform(String, Number)` round-trips `42` → `"42"` on encode.',
  async () => {
    const StringToNumber = Schema.transform(Schema.String, Schema.Number, {
      decode: (s) => Number.parseInt(s, 10),
      encode: (n) => String(n),
      strict: true,
    });
    const s = ESchema.make({ count: StringToNumber }).build();
    const out = await Effect.runPromise(s.encode({ count: 42 }));
    expect(out.count).toBe('42');
  },
);

vtest(
  'EntityESchema encode writes idField as a regular string',
  'The id column is just `Schema.String` — no branding, no transform.',
  async () => {
    const s = EntityESchema.make('User', 'id', {
      name: Schema.String,
    }).build();
    const out = await Effect.runPromise(
      s.encode({ id: 'u1', name: 'Alice' }),
    );
    expect(out.id).toBe('u1');
    expect(out.name).toBe('Alice');
  },
);

vtest(
  'encode of an invalid value fails with ESchemaError(message=Encode failed)',
  'A type mismatch in the input produces an `ESchemaError` whose message is `Encode failed`.',
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const result = await Effect.runPromise(
      s.encode({ a: 1 as unknown as string }).pipe(Effect.either),
    );
    expect(result._tag).toBe('Left');
    if (result._tag === 'Left') {
      expect(result.left).toBeInstanceOf(ESchemaError);
      expect(result.left.message).toBe('Encode failed');
    }
  },
);

vtest(
  'makePartial tags the value with _v without validating',
  'The returned object has `_v: latestVersion` and the original keys; no schema check runs.',
  () => {
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => ({ ...p, b: '' }))
      .build();
    const partial = s.makePartial({ a: 'x' });
    expect(partial._v).toBe('v2');
    expect(partial.a).toBe('x');
  },
);

vtest(
  'ESchemaError._tag is ESchemaError',
  '`Data.TaggedError` sets `_tag` so `Effect.catchTag` can match it across realms.',
  () => {
    const err = new ESchemaError({ message: 'x' });
    expect(err._tag).toBe('ESchemaError');
  },
);

vtest(
  'encode failure has message=Encode failed and a cause',
  'A type mismatch on encode wraps the Effect Schema `ParseError` as `cause`.',
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const result = await Effect.runPromise(
      s.encode({ a: 1 as unknown as string }).pipe(Effect.either),
    );
    if (result._tag === 'Left') {
      expect(result.left.message).toBe('Encode failed');
      expect(result.left.cause).toBeDefined();
    } else {
      throw new Error('expected Left');
    }
  },
);

vtest(
  'decode failure (bad shape) has message=Decode failed and a cause',
  "The struct decoder's `ParseError` is carried in `cause`; the wrapper message is constant.",
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const result = await Effect.runPromise(
      s.decode({ _v: 'v1', a: 42 }).pipe(Effect.either),
    );
    if (result._tag === 'Left') {
      expect(result.left.message).toBe('Decode failed');
      expect(result.left.cause).toBeDefined();
    } else {
      throw new Error('expected Left');
    }
  },
);

vtest(
  'decode of an unknown _v embeds the offending version string',
  'The rendered message is `Unknown schema version: <_v>` so logs identify the stale producer.',
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const result = await Effect.runPromise(
      s.decode({ _v: 'v42', a: 'x' }).pipe(Effect.either),
    );
    if (result._tag === 'Left') {
      expect(result.left.message).toContain('v42');
    } else {
      throw new Error('expected Left');
    }
  },
);

vtest(
  'catchTag recovers from decode failure',
  'A wrapped `ESchemaError` from `decode` is caught by the tag handler and replaced with a fallback.',
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const recovered = await Effect.runPromise(
      s
        .decode({ _v: 'v1', a: 42 })
        .pipe(
          Effect.catchTag('ESchemaError', () =>
            Effect.succeed({ a: 'fallback' }),
          ),
        ),
    );
    expect(recovered).toEqual({ a: 'fallback' });
  },
);

vtest(
  'catchTag recovers from unknown version failure',
  'Version-mismatch errors share the same `_tag`, so a single `catchTag` handler covers them too.',
  async () => {
    const s = ESchema.make({ a: Schema.String }).build();
    const recovered = await Effect.runPromise(
      s
        .decode({ _v: 'v99', a: 'x' })
        .pipe(
          Effect.catchTag('ESchemaError', () =>
            Effect.succeed({ a: 'fallback' }),
          ),
        ),
    );
    expect(recovered).toEqual({ a: 'fallback' });
  },
);

vtest(
  'v1 → v2 → v3 chain assembles in order',
  'The builder accepts `NextVersion<TVersion>` literals only; the latest version after two evolutions is `v3`.',
  () => {
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => ({ ...p, b: '' }))
      .evolve('v3', { c: Schema.Number }, (p) => ({ ...p, c: 0 }))
      .build();
    expect(s.latestVersion).toBe('v3');
  },
);

vtest(
  '.fields returns the latest merged schema, not a union',
  'Reading `.fields` after `.evolve()` reflects the final shape — earlier evolutions are not visible.',
  () => {
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => ({ ...p, b: '' }))
      .build();
    expect(Object.keys(s.fields).sort()).toEqual(['a', 'b']);
  },
);

vtest(
  'a null delta entry removes the field from .fields',
  'After `.evolve("v2", { legacy: null }, …)` the `legacy` key is not present on `.fields`.',
  () => {
    const s = ESchema.make({ a: Schema.String, legacy: Schema.String })
      .evolve('v2', { legacy: null }, (p) => ({ a: p.a }))
      .build();
    expect('legacy' in s.fields).toBe(false);
  },
);

vtest(
  'a non-null delta entry adds the field to .fields',
  'Adding a field with `.evolve()` makes it appear on `.fields` immediately.',
  () => {
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.Number }, (p) => ({ ...p, b: 0 }))
      .build();
    expect('b' in s.fields).toBe(true);
  },
);

vtest(
  'rename (remove + add) survives a v1 decode',
  'A v1 row is migrated through the rename and emerges at the new key.',
  async () => {
    const s = ESchema.make({
      firstName: Schema.String,
      lastName: Schema.String,
    })
      .evolve(
        'v2',
        {
          firstName: null,
          lastName: null,
          fullName: Schema.String,
        },
        (p) => ({ fullName: `${p.firstName} ${p.lastName}` }),
      )
      .build();
    const out = await Effect.runPromise(
      s.decode({ _v: 'v1', firstName: 'John', lastName: 'Doe' }),
    );
    expect(out).toEqual({ fullName: 'John Doe' });
  },
);

vtest(
  'migration is invoked only for older versions',
  'A row already at the latest version skips every migration step.',
  async () => {
    let calls = 0;
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => {
        calls += 1;
        return { ...p, b: '' };
      })
      .build();
    await Effect.runPromise(s.decode({ _v: 'v2', a: 'x', b: 'y' }));
    expect(calls).toBe(0);
  },
);

vtest(
  'migration sees the previous decoded shape',
  "The migration argument matches the previous evolution's struct, not the raw input row.",
  async () => {
    let seen: unknown;
    const s = ESchema.make({ a: Schema.String })
      .evolve('v2', { b: Schema.String }, (p) => {
        seen = p;
        return { ...p, b: 'added' };
      })
      .build();
    await Effect.runPromise(s.decode({ _v: 'v1', a: 'hi' }));
    expect(seen).toEqual({ a: 'hi' });
  },
);

vtest(
  'idField appears on .fields after every evolution',
  'A v2 entity still has its id field even though the v2 delta only added new columns.',
  () => {
    const s = EntityESchema.make('User', 'id', { name: Schema.String })
      .evolve('v2', { age: Schema.Number }, (p) => ({ ...p, age: 0 }))
      .build();
    expect('id' in s.fields).toBe(true);
  },
);

vtest(
  'EntityESchema.evolve rejects the id field in the delta at type level',
  'A delta that mentions the id field collides with `ForbidIdField<D, IdField>` at compile time.',
  () => {
    const builder = EntityESchema.make('User', 'id', {
      name: Schema.String,
    });
    // @ts-expect-error — `id` is reserved as the id field.
    builder.evolve('v2', { id: Schema.String }, (p) => p);
    expect(true).toBe(true);
  },
);

vtest(
  'toSchema round-trips a v1 row through the parent decoder, fully migrated',
  'A row stamped `_v: "v1"` inside an envelope ends up at the latest shape after parent decode.',
  async () => {
    const Envelope = Schema.Struct({ payload: toSchema(v1tov2) });
    const out = await Effect.runPromise(
      Schema.decodeUnknown(Envelope)({
        payload: { _v: 'v1', a: 'A' },
      }),
    );
    expect(out.payload).toEqual({ a: 'A', b: 'B' });
  },
);

vtest(
  'toSchema maps ESchemaError to ParseResult.Type with the error message',
  'A failed embedded decode surfaces as a parent `ParseError` carrying the original `ESchemaError.message`.',
  async () => {
    const Envelope = Schema.Struct({ payload: toSchema(v1tov2) });
    const result = await Effect.runPromise(
      Schema.decodeUnknown(Envelope)({
        payload: { _v: 'v99', a: 'A' },
      }).pipe(Effect.either),
    );
    expect(result._tag).toBe('Left');
  },
);

vtest(
  'getDescriptor includes _v as a literal at the latest version',
  "The descriptor's `properties._v.const` is `latestVersion`.",
  () => {
    const desc = v1tov2.getDescriptor();
    const props = (
      desc as unknown as {
        properties: Record<string, { enum?: string[] }>;
      }
    ).properties;
    expect(props._v?.enum).toEqual(['v2']);
  },
);

vtest(
  '~standard.vendor is @std-toolkit/eschema and version is 1',
  'These values are part of the public contract with Standard Schema consumers.',
  () => {
    expect(v1tov2['~standard'].vendor).toBe('@std-toolkit/eschema');
    expect(v1tov2['~standard'].version).toBe(1);
  },
);

vtest(
  '~standard.validate returns { value } on success',
  'A valid row decodes to the latest shape; the result has `value` only, no `issues`.',
  () => {
    const r = v1tov2['~standard'].validate({ _v: 'v1', a: 'A' });
    expect('value' in r).toBe(true);
  },
);

vtest(
  '~standard.validate returns { issues: [{ message }] } on decode failure',
  'A type mismatch produces a single issue whose message is `Decode failed`.',
  () => {
    const r = v1tov2['~standard'].validate({ _v: 'v1', a: 1 });
    expect('issues' in r).toBe(true);
    if ('issues' in r) {
      expect(r.issues?.[0]?.message).toBe('Decode failed');
    }
  },
);

vtest(
  '~standard.validate returns the Unknown schema version message verbatim',
  'An unrecognised `_v` propagates through to the `issues[0].message` field.',
  () => {
    const r = v1tov2['~standard'].validate({ _v: 'v99', a: 'A' });
    expect('issues' in r).toBe(true);
    if ('issues' in r) {
      expect(r.issues?.[0]?.message).toContain('v99');
    }
  },
);

vtest(
  'ESchema.make builds a v1-only schema',
  'No `.evolve()` is required to reach a usable schema.',
  () => {
    const s = ESchema.make({ theme: Schema.String }).build();
    expect(s.latestVersion).toBe('v1');
    expect(Object.keys(s.fields)).toContain('theme');
  },
);

vtest(
  'SingleEntityESchema.make exposes .name',
  'The name supplied to `make` is stored on the built schema and survives `.evolve()`.',
  () => {
    const s = SingleEntityESchema.make('Settings', {
      locale: Schema.String,
    }).build();
    expect(s.name).toBe('Settings');
    expect(s.latestVersion).toBe('v1');
  },
);

vtest(
  'EntityESchema.make exposes .name and .idField',
  'Identity is `{ name, idField }`; both are surfaced on the built schema.',
  () => {
    const s = EntityESchema.make('User', 'id', {
      name: Schema.String,
    }).build();
    expect(s.name).toBe('User');
    expect(s.idField).toBe('id');
  },
);

vtest(
  'idField is present on .fields after make',
  'A pre-`.evolve()` schema already carries the id column on `.fields`.',
  () => {
    const s = EntityESchema.make('User', 'id', {
      name: Schema.String,
    }).build();
    expect('id' in s.fields).toBe(true);
  },
);

vtest(
  'idField is preserved across evolutions',
  'Each `.evolve()` re-injects the id field, even if the delta does not mention it.',
  () => {
    const s = EntityESchema.make('User', 'id', {
      name: Schema.String,
    })
      .evolve('v2', { age: Schema.Number }, (p) => ({ ...p, age: 0 }))
      .build();
    expect('id' in s.fields).toBe(true);
    expect('age' in s.fields).toBe(true);
  },
);

vtest(
  'underscore-prefixed keys are forbidden at type level',
  'The `ForbidUnderscorePrefix<I>` constraint maps `_*` keys to a string literal type, surfacing as a TypeScript error in user code.',
  () => {
    // @ts-expect-error — `_internal` collides with the metadata namespace.
    ESchema.make({ _internal: Schema.String });
    expect(true).toBe(true);
  },
);

vtest(
  'EntityESchema rejects an explicit id field at type level',
  '`ForbidIdField<I, Id>` rejects any user-supplied key equal to `idField`, even though the library adds the same name itself.',
  () => {
    // @ts-expect-error — `id` is reserved as the id field.
    EntityESchema.make('X', 'id', {
      id: Schema.String,
      name: Schema.String,
    });
    expect(true).toBe(true);
  },
);
